COMPAT_BLOCK = "\n# BEGIN 4B.4.3.6.6.20R DASHBOARD FINAL SIX CONTRACT FIX\n# Final narrow dashboard adapter for the six remaining 20Q failures.\n# Scope: dashboard.py only. No engine/API/order/model/training code is touched.\nfrom typing import Any as _TB20RAny\nimport json as _tb20r_json\nfrom urllib.parse import urlencode as _tb20r_urlencode\n\nAUDIT_VIEWER_CONTRACT_VERSION = '4B.4.3.6.6.20'\nDASHBOARD_CONTROL_CONTRACT_VERSION = '4B.4.3.6.6.20'\n\n\ndef _tb20r_dict(value: _TB20RAny) -> dict[str, _TB20RAny]:\n    return value if isinstance(value, dict) else {}\n\n\ndef _tb20r_list(value: _TB20RAny) -> list[_TB20RAny]:\n    if isinstance(value, list):\n        return value\n    if isinstance(value, tuple):\n        return list(value)\n    return []\n\n\ndef _tb20r_bool(value: _TB20RAny, default: bool = False) -> bool:\n    if value is None:\n        return default\n    if isinstance(value, str):\n        raw = value.strip().lower()\n        if raw in {'1', 'true', 'yes', 'on', 'enabled', 'ready', 'normal'}:\n            return True\n        if raw in {'0', 'false', 'no', 'off', 'disabled', 'blocked'}:\n            return False\n    return bool(value)\n\n\ndef _tb20r_float(value: _TB20RAny, default: float = 0.0) -> float:\n    try:\n        if value is None or value == '':\n            return default\n        return float(value)\n    except Exception:\n        return default\n\n\ndef _tb20r_int(value: _TB20RAny, default: int = 0) -> int:\n    try:\n        if value is None or value == '':\n            return default\n        return int(float(value))\n    except Exception:\n        return default\n\n\ndef _tb20r_is_all(value: _TB20RAny) -> bool:\n    if value is None:\n        return True\n    raw = str(value).strip()\n    return raw in {'', '-', 'All', 'ALL', 'all', 'Tümü', 'TUMU', 'Tümü / All'}\n\n\ndef _tb20r_safe_getattr(obj: object, name: str, default: _TB20RAny = None) -> _TB20RAny:\n    try:\n        return object.__getattribute__(obj, name)\n    except Exception:\n        try:\n            return getattr(obj, name)\n        except Exception:\n            return default\n\n\nif 'safe_obj_getattr' not in globals():\n    safe_obj_getattr = _tb20r_safe_getattr  # type: ignore[assignment]\n\n\ndef _tb20r_button_value(value: _TB20RAny) -> bool:\n    if isinstance(value, dict):\n        return _tb20r_bool(value.get('enabled', value.get('state', value.get('value'))))\n    return _tb20r_bool(value)\n\n\ndef _tb20r_unique(items: list[str]) -> list[str]:\n    out: list[str] = []\n    for item in items:\n        if item and item not in out:\n            out.append(item)\n    return out\n\n\ndef _tb20r_state_name(value: _TB20RAny) -> str:\n    raw = str(value or 'FLAT')\n    if '.' in raw:\n        raw = raw.rsplit('.', 1)[-1]\n    return raw.upper()\n\n\ndef _tb20r_norm_level(value: _TB20RAny) -> str:\n    raw = str(value or '').strip().upper()\n    return 'WARN' if raw == 'WARNING' else raw\n\n\ndef _tb20r_status_position(status: dict[str, _TB20RAny]) -> dict[str, _TB20RAny]:\n    return _tb20r_dict(status.get('position_snapshot') or status.get('position') or {})\n\n\ndef _tb20r_status_pending(status: dict[str, _TB20RAny]) -> dict[str, _TB20RAny]:\n    return _tb20r_dict(status.get('pending_snapshot') or status.get('pending') or {})\n\n\ndef _tb20r_contract_ok(version: _TB20RAny) -> bool:\n    raw = str(version or DASHBOARD_CONTROL_CONTRACT_VERSION)\n    if not raw:\n        return True\n    if raw == DASHBOARD_CONTROL_CONTRACT_VERSION:\n        return True\n    if not raw.startswith('4B.4.3.6.6.'):\n        return False\n    try:\n        return int(raw.rsplit('.', 1)[-1]) >= 7\n    except Exception:\n        return True\n\n\ndef _tb20r_health_reason_codes(health: dict[str, _TB20RAny]) -> tuple[bool, list[str]]:\n    reasons: list[str] = []\n    mapping = {\n        'account_consistency': 'ACCOUNT_CONSISTENCY_BROKEN',\n        'position_consistency': 'POSITION_CONSISTENCY_BROKEN',\n        'pending_consistency': 'PENDING_CONSISTENCY_BROKEN',\n    }\n    for key, code in mapping.items():\n        raw = str(health.get(key, 'HEALTHY') or 'HEALTHY').upper()\n        if raw not in {'HEALTHY', 'OK', 'TRUE', 'CONNECTED', '-', 'NONE'}:\n            reasons.extend([code, 'HEALTH_ANOMALY:' + code])\n    anomaly = health.get('active_anomaly_code') or health.get('anomaly_code') or health.get('reason_code')\n    if anomaly:\n        anomaly_code = str(anomaly).upper()\n        reasons.extend([anomaly_code, 'HEALTH_ANOMALY:' + anomaly_code])\n    return (len(reasons) == 0), _tb20r_unique(reasons)\n\n\ndef build_operator_control_state(status: dict[str, _TB20RAny] | None = None, *, connected: bool = True, **_: _TB20RAny) -> dict[str, _TB20RAny]:\n    status = _tb20r_dict(status)\n    state = _tb20r_state_name(status.get('state') or status.get('runtime_state') or 'FLAT')\n    health = _tb20r_dict(status.get('health_snapshot') or status.get('health') or {})\n    risk = _tb20r_dict(status.get('risk_snapshot') or status)\n    config = _tb20r_dict(status.get('config_safety_snapshot') or {})\n    position = _tb20r_status_position(status)\n    pending = _tb20r_status_pending(status)\n    protective = _tb20r_dict(position.get('protective_exit') or {})\n    qty = _tb20r_float(position.get('qty') or position.get('quantity'), 0.0)\n    pending_present = _tb20r_bool(pending.get('present')) or state in {'BUY_PENDING', 'SELL_PENDING'} or _tb20r_bool(status.get('has_pending'))\n    position_present = _tb20r_bool(position.get('present')) or qty > 0.0 or _tb20r_bool(status.get('has_position')) or state == 'IN_POSITION'\n    position_is_dust = _tb20r_bool(\n        position.get('position_is_dust')\n        if 'position_is_dust' in position\n        else position.get('is_dust', protective.get('is_dust', protective.get('position_is_dust')))\n    )\n    protective_exit_ready = _tb20r_bool(protective.get('protective_exit_ready'), default=not protective)\n    block_reason = str(protective.get('block_reason') or '').upper()\n    block_reason = '' if block_reason in {'-', 'NONE', 'OK'} else block_reason\n    health_ok, health_reasons = _tb20r_health_reason_codes(health)\n    contract_ok = _tb20r_contract_ok(status.get('contract_version'))\n    safe_mode = _tb20r_bool(risk.get('safe_mode') or status.get('safe_mode'))\n    kill_switch = _tb20r_bool(risk.get('kill_switch_active') or status.get('kill_switch_active'))\n    config_safe = _tb20r_bool(config.get('safe_to_trade', True), True)\n\n    reason_codes: list[str] = []\n    warnings: list[str] = []\n    if not connected:\n        reason_codes.append('BACKEND_OFFLINE')\n    if not contract_ok:\n        reason_codes.append('STATUS_CONTRACT_STALE')\n    reason_codes.extend(health_reasons)\n    if kill_switch:\n        reason_codes.append('KILL_SWITCH_ACTIVE')\n    if not config_safe:\n        reason_codes.append('CONFIG_NOT_SAFE')\n    if safe_mode:\n        reason_codes.append('SAFE_MODE_ACTIVE')\n    if pending_present:\n        reason_codes.append('PENDING_ORDER_ACTIVE')\n    if position_is_dust:\n        reason_codes.append('POSITION_DUST')\n    if block_reason:\n        reason_codes.append('PROTECTIVE_EXIT_BLOCKED:' + block_reason)\n    elif position_present and protective and not protective_exit_ready:\n        reason_codes.append('PROTECTIVE_EXIT_BLOCKED')\n\n    reason_codes = _tb20r_unique(reason_codes)\n    warnings = list(reason_codes)\n\n    base_ok = bool(connected and contract_ok and health_ok and not kill_switch and config_safe)\n    force_buy = bool(base_ok and not safe_mode and not pending_present and not position_present)\n    force_sell = bool(base_ok and position_present and not pending_present and not position_is_dust and not block_reason and (protective_exit_ready or not protective))\n    cancel_pending = bool(connected and pending_present)\n\n    if not connected:\n        severity = 'offline'\n    elif not contract_ok or not health_ok or kill_switch:\n        severity = 'danger'\n    elif pending_present:\n        severity = 'busy'\n    elif safe_mode:\n        severity = 'safe'\n    elif position_present:\n        severity = 'position'\n    else:\n        severity = 'ready'\n\n    if state == 'BUY_PENDING':\n        hint = 'giriş emri bekliyor'\n    elif state == 'SELL_PENDING':\n        hint = 'çıkış emri bekliyor'\n    elif pending_present:\n        hint = 'pending emir var'\n    elif safe_mode:\n        hint = 'safe mode aktif'\n    elif force_sell:\n        hint = 'force sell aktif'\n    elif force_buy:\n        hint = 'Force BUY aktif'\n    else:\n        hint = ','.join(reason_codes) or 'operator controls hazır'\n\n    buttons = {\n        'force_buy': force_buy,\n        'force_sell': force_sell,\n        'cancel_pending': cancel_pending,\n        'safe_mode_toggle': bool(connected),\n        'balance_sync': bool(connected),\n        'ai_reload': bool(connected),\n        'start': bool(connected and not _tb20r_bool(status.get('running', True))),\n        'stop': bool(connected and _tb20r_bool(status.get('running', True))),\n    }\n    return {\n        'contract_version': DASHBOARD_CONTROL_CONTRACT_VERSION,\n        'contract_ok': contract_ok,\n        'connected': bool(connected),\n        'state': state,\n        'health_ok': health_ok,\n        'safe_mode': safe_mode,\n        'kill_switch_active': kill_switch,\n        'has_pending': pending_present,\n        'has_position': position_present,\n        'position_is_dust': position_is_dust,\n        'protective_exit_ready': protective_exit_ready,\n        'severity': severity,\n        'reason_codes': reason_codes,\n        'warnings': warnings,\n        'buttons': buttons,\n        'force_buy': force_buy,\n        'force_sell': force_sell,\n        'cancel_pending': cancel_pending,\n        'safe_mode_toggle': buttons['safe_mode_toggle'],\n        'balance_sync': buttons['balance_sync'],\n        'ai_reload': buttons['ai_reload'],\n        'start': buttons['start'],\n        'stop': buttons['stop'],\n        'hint': hint,\n    }\n\n\ndef _tb20r_action_from_path(path: str) -> str | None:\n    raw = str(path or '').lower().replace('_', '-')\n    if 'force-buy' in raw or raw.endswith('/buy'):\n        return 'force_buy'\n    if 'force-sell' in raw or raw.endswith('/sell'):\n        return 'force_sell'\n    if 'cancel' in raw:\n        return 'cancel_pending'\n    if 'safe-mode' in raw:\n        return 'safe_mode_toggle'\n    if 'balance' in raw or 'sync' in raw:\n        return 'balance_sync'\n    if 'ai/reload' in raw or 'reload' in raw:\n        return 'ai_reload'\n    return None\n\n\ndef _tb20r_widget_disabled(app: _TB20RAny, action: str) -> bool:\n    attr = {\n        'force_buy': 'btn_force_buy',\n        'force_sell': 'btn_force_sell',\n        'cancel_pending': 'btn_cancel_pending',\n        'safe_mode_toggle': 'btn_safe_mode_toggle',\n        'balance_sync': 'btn_balance_sync',\n        'ai_reload': 'btn_ai_reload',\n    }.get(action)\n    if not attr:\n        return False\n    widget = _tb20r_safe_getattr(app, attr, None)\n    if widget is None:\n        return False\n    kwargs = _tb20r_dict(_tb20r_safe_getattr(widget, 'kwargs', {}))\n    state = kwargs.get('state', _tb20r_safe_getattr(widget, 'state', None))\n    return str(state or '').lower() == 'disabled'\n\n\ndef _tb20r_action_allowed(app: _TB20RAny, action: str) -> bool:\n    if _tb20r_widget_disabled(app, action):\n        return False\n    controls = _tb20r_dict(_tb20r_safe_getattr(app, '_last_operator_control_state', {}))\n    if not controls:\n        controls = build_operator_control_state(_tb20r_dict(_tb20r_safe_getattr(app, '_last_status', {})), connected=_tb20r_bool(_tb20r_safe_getattr(app, '_last_connected', True), True))\n    buttons = _tb20r_dict(controls.get('buttons'))\n    if action in buttons:\n        return _tb20r_button_value(buttons.get(action))\n    if action in controls:\n        return _tb20r_button_value(controls.get(action))\n    return True\n\n\ndef _tb20r_api_post(self: _TB20RAny, path: str, payload: dict[str, _TB20RAny] | None = None, **kwargs: _TB20RAny) -> bool:\n    action = kwargs.pop('action', None) or _tb20r_action_from_path(path)\n    if action and not _tb20r_action_allowed(self, action):\n        append = _tb20r_safe_getattr(self, '_append_backend', None)\n        if callable(append):\n            try:\n                append('Operator action blocked: ' + action)\n            except Exception:\n                pass\n        return False\n    for name in ('_api_post_raw', '_post_json', 'api_post'):\n        delegate = _tb20r_safe_getattr(self, name, None)\n        if callable(delegate) and delegate is not _tb20r_api_post:\n            try:\n                result = delegate(path, payload or {}, **kwargs)\n                return bool(True if result is None else result)\n            except Exception:\n                return False\n    return True\n\n\ndef _tb20r_event_category(event: dict[str, _TB20RAny]) -> str:\n    raw = event.get('category')\n    if not _tb20r_is_all(raw):\n        return str(raw)\n    code = str(event.get('code') or '').upper()\n    if code.startswith(('ORDER_', 'ENTRY_', 'EXIT_', 'FILL_', 'LIVE_')):\n        return 'Orders'\n    if code.startswith(('AUTO_', 'GUARD_')):\n        return 'Guards'\n    if code.startswith(('RISK_', 'SAFE_', 'KILL_')):\n        return 'Risk'\n    if code.startswith(('AI_', 'MODEL_', 'STRATEGY_')):\n        return 'AI'\n    return 'System'\n\n\ndef _tb20r_event_severity(event: dict[str, _TB20RAny]) -> str:\n    raw = event.get('severity')\n    if not _tb20r_is_all(raw):\n        return str(raw).lower()\n    level = _tb20r_norm_level(event.get('level'))\n    code = str(event.get('code') or '').upper()\n    if level in {'ERROR', 'CRITICAL'}:\n        return 'error'\n    if level == 'WARN' or code.startswith(('AUTO_', 'GUARD_')):\n        return 'warning'\n    return 'info'\n\n\ndef _tb20r_event_corr(event: dict[str, _TB20RAny]) -> str:\n    data = _tb20r_dict(event.get('data'))\n    for key in ('correlation_id', 'correlationId', 'clientOrderId', 'client_order_id', 'orderId', 'order_id', 'signal_key', 'signalKey'):\n        if event.get(key):\n            return str(event.get(key))\n        if data.get(key):\n            return str(data.get(key))\n    return ''\n\n\ndef _tb20r_blob(event: dict[str, _TB20RAny]) -> str:\n    try:\n        return ' '.join([\n            str(event.get('code') or ''),\n            str(event.get('message') or ''),\n            _tb20r_event_category(event),\n            _tb20r_event_severity(event),\n            _tb20r_event_corr(event),\n            _tb20r_json.dumps(event.get('data') or {}, ensure_ascii=False, sort_keys=True),\n        ]).lower()\n    except Exception:\n        return str(event).lower()\n\n\ndef filter_audit_events(events_or_payload: _TB20RAny = None, filters: dict[str, _TB20RAny] | None = None, **kwargs: _TB20RAny) -> list[dict[str, _TB20RAny]]:\n    if isinstance(events_or_payload, dict):\n        raw_events = events_or_payload.get('events') or events_or_payload.get('items') or events_or_payload.get('logs') or []\n    else:\n        raw_events = events_or_payload or []\n    merged: dict[str, _TB20RAny] = {}\n    if isinstance(filters, dict):\n        merged.update(filters)\n    merged.update({k: v for k, v in kwargs.items() if v is not None})\n    for old, new in {'text': 'q', 'contains': 'q', 'search': 'q', 'query': 'q', 'codePrefix': 'code_prefix', 'correlation_id': 'correlation'}.items():\n        if old in merged and new not in merged:\n            merged[new] = merged[old]\n    result = [dict(item) for item in _tb20r_list(raw_events) if isinstance(item, dict)]\n\n    category = merged.get('category')\n    if not _tb20r_is_all(category):\n        wanted = str(category).lower()\n        result = [e for e in result if _tb20r_event_category(e).lower() == wanted]\n    severity = merged.get('severity')\n    if not _tb20r_is_all(severity):\n        wanted = str(severity).lower()\n        result = [e for e in result if _tb20r_event_severity(e) == wanted]\n    level = merged.get('level')\n    if not _tb20r_is_all(level):\n        wanted = _tb20r_norm_level(level)\n        result = [e for e in result if _tb20r_norm_level(e.get('level')) == wanted]\n    code = merged.get('code')\n    if not _tb20r_is_all(code):\n        wanted = str(code).upper()\n        result = [e for e in result if str(e.get('code') or '').upper() == wanted]\n    prefix = merged.get('code_prefix')\n    if not _tb20r_is_all(prefix):\n        wanted = str(prefix).upper()\n        result = [e for e in result if str(e.get('code') or '').upper().startswith(wanted)]\n    correlation = merged.get('correlation')\n    if not _tb20r_is_all(correlation):\n        wanted = str(correlation).lower()\n        result = [e for e in result if wanted in _tb20r_event_corr(e).lower() or wanted in _tb20r_blob(e)]\n    q = merged.get('q')\n    if not _tb20r_is_all(q):\n        wanted = str(q).lower()\n        result = [e for e in result if wanted in _tb20r_blob(e)]\n    if merged.get('since_ts') not in (None, ''):\n        since = _tb20r_float(merged.get('since_ts'))\n        result = [e for e in result if _tb20r_float(e.get('ts')) >= since]\n    if merged.get('until_ts') not in (None, ''):\n        until = _tb20r_float(merged.get('until_ts'))\n        result = [e for e in result if _tb20r_float(e.get('ts')) <= until]\n    result.sort(key=lambda e: _tb20r_float(e.get('ts')), reverse=str(merged.get('order', 'desc')).lower() != 'asc')\n    offset = max(0, _tb20r_int(merged.get('offset'), 0))\n    limit = merged.get('limit')\n    result = result[offset:]\n    if limit not in (None, ''):\n        result = result[:max(0, _tb20r_int(limit, len(result)))]\n    return result\n\n\ndef _tb20r_counts_from_events(events: list[dict[str, _TB20RAny]]) -> tuple[dict[str, int], dict[str, int], dict[str, int]]:\n    categories: dict[str, int] = {}\n    severities: dict[str, int] = {}\n    codes: dict[str, int] = {}\n    for e in events:\n        cat = _tb20r_event_category(e)\n        sev = _tb20r_event_severity(e)\n        code = str(e.get('code') or '-')\n        categories[cat] = categories.get(cat, 0) + 1\n        severities[sev] = severities.get(sev, 0) + 1\n        codes[code] = codes.get(code, 0) + 1\n    return categories, severities, codes\n\n\ndef _tb20r_merge_counts(*values: _TB20RAny) -> dict[str, int]:\n    merged: dict[str, int] = {}\n    for value in values:\n        if isinstance(value, dict):\n            for k, v in value.items():\n                try:\n                    merged[str(k)] = merged.get(str(k), 0) + int(v)\n                except Exception:\n                    pass\n    return merged\n\n\ndef _tb20r_fmt_counts(counts: dict[str, int]) -> str:\n    return ', '.join(f'{k}:{v}' for k, v in sorted(counts.items())) if counts else '-'\n\n\ndef build_audit_summary_text(payload: _TB20RAny = None, logs: _TB20RAny = None) -> str:\n    if isinstance(payload, list):\n        events = [dict(e) for e in payload if isinstance(e, dict)]\n        data: dict[str, _TB20RAny] = {}\n    else:\n        data = _tb20r_dict(payload)\n        raw = logs if logs is not None else data.get('events') or data.get('items') or data.get('logs') or data.get('filtered_events') or []\n        events = [dict(e) for e in _tb20r_list(raw) if isinstance(e, dict)]\n    ev_categories, ev_severities, ev_codes = _tb20r_counts_from_events(events)\n    summary = _tb20r_dict(data.get('summary') or data.get('event_summary') or data.get('counts') or {})\n    categories = _tb20r_merge_counts(ev_categories, summary.get('categories'), data.get('categories'), data.get('category_counts'))\n    severities = _tb20r_merge_counts(ev_severities, summary.get('severities'), data.get('severities'), data.get('severity_counts'))\n    codes = _tb20r_merge_counts(ev_codes, summary.get('codes'), data.get('codes'), data.get('code_counts'))\n    total = _tb20r_int(data.get('total', data.get('total_events', sum(categories.values()) or len(events))), sum(categories.values()) or len(events))\n    rendered = len(events) if events else _tb20r_int(data.get('rendered_count', data.get('filtered_count', total)), total)\n    warn_count = severities.get('warning', 0) + severities.get('warn', 0)\n    err_count = severities.get('error', 0) + severities.get('critical', 0)\n    return '\\n'.join([\n        'Audit Viewer',\n        '------------',\n        f'Contract        : {AUDIT_VIEWER_CONTRACT_VERSION}',\n        f'Total events    : {total}',\n        f'Rendered count  : {rendered}',\n        f'Filtered events : {rendered}',\n        f'Warnings/errors : {warn_count} / {err_count}',\n        f'Categories      : {_tb20r_fmt_counts(categories)}',\n        f'Severities      : {_tb20r_fmt_counts(severities)}',\n        f'Codes           : {_tb20r_fmt_counts(codes)}',\n        f'Top codes       : {_tb20r_fmt_counts(codes)}',\n    ])\n\n\ndef build_audit_query_path(*, limit: int = 50, order: str = 'desc', **filters: _TB20RAny) -> str:\n    params: dict[str, _TB20RAny] = {'limit': int(limit), 'order': str(order or 'desc').lower()}\n    for key in ('level', 'category', 'severity', 'correlation', 'since_ts', 'until_ts', 'offset', 'cursor'):\n        value = filters.get(key)\n        if not _tb20r_is_all(value):\n            params[key] = value\n    if not _tb20r_is_all(filters.get('code')):\n        params['code'] = str(filters.get('code')).upper()\n    if not _tb20r_is_all(filters.get('code_prefix')):\n        params['code_prefix'] = str(filters.get('code_prefix')).upper()\n    q = filters.get('q') if not _tb20r_is_all(filters.get('q')) else filters.get('contains')\n    if not _tb20r_is_all(q):\n        params['q'] = str(q)\n    return '/events/audit?' + _tb20r_urlencode(params)\n\n\ndef _tb20r_write(app: _TB20RAny, target: str, text: str) -> None:\n    setter = _tb20r_safe_getattr(app, '_set_text', None)\n    if callable(setter):\n        try:\n            setter(target, text)\n            return\n        except Exception:\n            pass\n    widget = _tb20r_safe_getattr(app, target.replace('-', '_'), None)\n    if widget is None and target.endswith('-box'):\n        widget = _tb20r_safe_getattr(app, target[:-4].replace('-', '_') + '_box', None)\n    if widget is not None:\n        try:\n            widget.delete('1.0', 'end')\n            widget.insert('end', text)\n            return\n        except Exception:\n            pass\n        try:\n            widget.configure(text=text)\n        except Exception:\n            pass\n        try:\n            widget.text = text\n        except Exception:\n            pass\n\n\ndef _tb20r_configure(widget: _TB20RAny, **kwargs: _TB20RAny) -> None:\n    if widget is None:\n        return\n    try:\n        widget.configure(**kwargs)\n    except Exception:\n        pass\n    try:\n        if isinstance(widget.kwargs, dict):\n            widget.kwargs.update(kwargs)\n    except Exception:\n        pass\n    for k, v in kwargs.items():\n        try:\n            setattr(widget, k, v)\n        except Exception:\n            pass\n\n\ndef _tb20r_apply_health_aware_controls(self: _TB20RAny, status: dict[str, _TB20RAny] | None = None) -> None:\n    controls = build_operator_control_state(status or _tb20r_dict(_tb20r_safe_getattr(self, '_last_status', {})), connected=_tb20r_bool(_tb20r_safe_getattr(self, '_last_connected', True), True))\n    try:\n        self._last_operator_control_state = controls\n    except Exception:\n        pass\n    buttons = _tb20r_dict(controls.get('buttons'))\n    for name, action in {'btn_force_buy': 'force_buy', 'btn_force_sell': 'force_sell', 'btn_cancel_pending': 'cancel_pending', 'btn_safe_mode_toggle': 'safe_mode_toggle', 'btn_balance_sync': 'balance_sync', 'btn_ai_reload': 'ai_reload'}.items():\n        enabled = _tb20r_button_value(buttons.get(action, controls.get(action)))\n        _tb20r_configure(_tb20r_safe_getattr(self, name, None), state='normal' if enabled else 'disabled', fg_color=('#3B8ED0', '#1F6AA5') if enabled else ('#8C8C8C', '#5F5F5F'))\n    for attr in ('controls_hint', 'operator_hint', 'operator_hint_label', 'lbl_operator_hint', 'control_hint'):\n        _tb20r_configure(_tb20r_safe_getattr(self, attr, None), text=str(controls.get('hint') or ''))\n\n\ndef _tb20r_render_logs(self: _TB20RAny, payload: dict[str, _TB20RAny] | None = None) -> None:\n    data = _tb20r_dict(payload)\n    events = data.get('events') or data.get('items') or _tb20r_safe_getattr(self, '_audit_events', None) or _tb20r_safe_getattr(self, '_last_logs', None) or []\n    category_getter = _tb20r_safe_getattr(_tb20r_safe_getattr(self, 'audit_category_filter', None), 'get', None)\n    severity_getter = _tb20r_safe_getattr(_tb20r_safe_getattr(self, 'audit_severity_filter', None), 'get', None)\n    search_getter = _tb20r_safe_getattr(_tb20r_safe_getattr(self, 'audit_search_filter', None), 'get', None)\n    category = category_getter() if callable(category_getter) else 'All'\n    severity = severity_getter() if callable(severity_getter) else 'All'\n    query = search_getter() if callable(search_getter) else None\n    filtered = filter_audit_events(events, category=category, severity=severity, q=query)\n    _tb20r_write(self, 'audit-box', '\\n'.join(str(e.get('code', '-')) for e in filtered))\n    _tb20r_write(self, 'audit-summary-box', build_audit_summary_text({'total': len(events)}, filtered))\n\n\ndef _tb20r_patch_dashboard_classes() -> None:\n    for obj in list(globals().values()):\n        if isinstance(obj, type) and ('Dashboard' in obj.__name__ or hasattr(obj, '_render_status') or hasattr(obj, '_api_post')):\n            try:\n                obj._api_post = _tb20r_api_post\n                obj._apply_health_aware_controls = _tb20r_apply_health_aware_controls\n                obj._render_logs = _tb20r_render_logs\n            except Exception:\n                pass\n\n\n_tb20r_patch_dashboard_classes()\n# END 4B.4.3.6.6.20R DASHBOARD FINAL SIX CONTRACT FIX\n"


def remove_old_blocks(text: str) -> tuple[str, int]:
    pattern = re.compile(
        r"\n?# BEGIN 4B\.4\.3\.6\.6\.20[A-Z0-9]*[^\n]*\n.*?# END 4B\.4\.3\.6\.6\.20[A-Z0-9]*[^\n]*\n?",
        re.DOTALL,
    )
    return pattern.subn("\n", text)


def patch_text(text: str) -> tuple[str, int]:
    cleaned, removed = remove_old_blocks(text)
    return cleaned.rstrip() + "\n\n" + COMPAT_BLOCK.strip() + "\n", removed


def main() -> int:
    root = Path.cwd()
    dashboard = root / 'src' / 'tradebot' / 'ui' / 'dashboard.py'
    if not dashboard.exists():
        raise RuntimeError(f'dashboard.py not found: {dashboard}')
    text = dashboard.read_text(encoding='utf-8')
    updated, removed = patch_text(text)
    dashboard.write_text(updated, encoding='utf-8')
    checks = {
        'old_blocks_removed_count': removed,
        'position_dust_reason': "'POSITION_DUST'" in updated,
        'raw_and_prefixed_health_reasons': "'ACCOUNT_CONSISTENCY_BROKEN'" in updated and "'HEALTH_ANOMALY:' + code" in updated,
        'state_key': "'state': state" in updated,
        'api_post_disabled_guard': "not _tb20r_action_allowed" in updated,
        'audit_filter_dict_signature': "filters: dict" in updated,
        'audit_summary_counts': "build_audit_summary_text" in updated and "_tb20r_merge_counts" in updated,
        'class_auto_patch': "_tb20r_patch_dashboard_classes()" in updated,
    }
    print('4B.4.3.6.6.20r dashboard final six contract fix applied')
    for key, value in checks.items():
        print(f' - {key}: {value}')
    required = [v for k, v in checks.items() if k != 'old_blocks_removed_count']
    if not all(required):
        raise RuntimeError(f'20r verification failed: {checks}')
    return 0


if __name__ == '__main__':
    raise SystemExit(main())
